const rawWebhook = $('Webhook').first().json;
const webhook = rawWebhook.body || rawWebhook;

const schoolId = webhook.schoolId || '';
const assessmentName = webhook.assessmentName || 'Sodhana 1';

if (!schoolId) {
  throw new Error("Critical Error: 'schoolId' not found in Webhook data.");
}

const encodedAssessment = encodeURIComponent(assessmentName);
const pdfUrl = `https://viswam-report-card.vercel.app/api/reports/school/${schoolId}/pdf?assessmentName=${encodedAssessment}`;
const jsonPdfUrl = `${pdfUrl}&json=true`;

return [{
  json: {
    schoolId,
    assessmentName,
    pdfUrl,
    jsonPdfUrl,
    schoolName: webhook.schoolName || 'Unknown School',
    principalEmail: webhook.principalEmail || '',
    whatsappNo: webhook.whatsappNo || '',
    studentCount: webhook.studentCount || 0,
    timestamp: new Date().toISOString()
  }
}];
